    74	uint32_t ngap_generate_gNB_id(void)
    75	{
    76	  /* Retrieve the host name */
    77	  char hostname[32] = {0};
    78	  int const ret = gethostname(hostname, sizeof(hostname));
    79	  DevAssert(ret == 0);
    80	
    81	  uint8_t key[32] = {"eurecom"};
    82	  byte_array_t data = {.len = 32, .buf = (uint8_t *)hostname};
    83	
    84	  uint8_t out[32] = {0};
    85	  kdf(key, data, 32, out);
    86	
    87	  uint32_t const gNB_id = ((out[0] << 24) | (out[1] << 16) | (out[2] << 8) | out[3]);
    88	  return gNB_id;
    89	}
